mapper.insert:
INSERT INTO USER_USAGE_STAT (
    TYPE, RSRE_YMD, RSRE_YM, RSRE_Y,
    HDQR_BOB_DCD, TOTAL, HIT_CNT1, HIT_CNT2, HIT_CNT3, HIT_CNT4, ARIN_USE_CNT, TOTAL_OUTPUT_CNT
) VALUES (
     #{type}, #{rsreYmd}, SUBSTRING(#{rsreYmd},1,6), SUBSTRING(#{rsreYmd},1,4),
     #{hdqrBobDcd}, #{total}, #{hitCnt1}, #{hitCnt2}, #{hitCnt3}, #{hitCnt4}, #{arinUseCnt}, #{totalOutputCnt}
)
